import sys
from typing import List

class Solution:
    def maxRestoreXOR(self, nums: List[int], m: List[bool]) -> int:
        n = len(nums)
        restore = set()
        for i in range(n):
            if m[i]: restore.add(i)
        maxVal = 0
        for i in range(n):
            for j in range(i + 1, n):
                if i in restore and j in restore: maxVal = max(maxVal, nums[i] ^ nums[j])
        return maxVal

if __name__ == '__main__':
    nums = [int(x) for x in input().split()]
    m = [bool(x) for x in input().split()] 
    sol = Solution()
    print(sol.maxRestoreXOR(nums, m))

