#include <iostream>
#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

class Solution {
public:
    int maxRestoreXOR(vector<int>& nums, vector<bool>& m) {
        int n = nums.size();
        set<int> restore;
        for (int i = 0; i < n; i++) {
            if (m[i]) restore.insert(i);
        }
        int maxVal = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (restore.find(i) != restore.end() && restore.find(j) != restore.end()) maxVal = max(maxVal, nums[i] ^ nums[j]);
            }
        }
        return maxVal;

    }
};

int main() {
    vector<int> nums; 
    vector<bool> m; 
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        int x;
        cin >> x;
        nums.push_back(x);
    }
    m.resize(n);
    for (int i = 0; i < n; i++) {
        bool x;
        cin >> x;
        m[i] = x;
    }
    Solution sol;
    cout << sol.maxRestoreXOR(nums, m) << endl;
    return 0;
}
